20: int ringbuf_write(RingBuffer *rb, const unsigned char *data, size_t len) {
21:     if (len > rb->capacity - rb->count)
22:         return -1; // not enough space
23: 
24:     for (size_t i = 0; i < len; i++) {
25:         rb->buf[rb->head] = data[i];
26:         rb->head = (rb->head + 1) % (rb->capacity + 1);
27:     }
28:     rb->count += len;
29:     return 0;
